 use tokio::sync::oneshot;
-use std::time::Duration;
-
-/// Fail closed if no approver answers within this window.
-const APPROVAL_TIMEOUT: Duration = Duration::from_secs(180);

 pub enum Decision { Allow, Deny }

 /// Run a tool that needs human approval. The approver answers `decision_rx`.
-/// In a headless session there is NO interactive approver, so `decision_rx`
-/// is never resolved — the timeout is what guarantees this still terminates.
+/// In a headless session there is NO interactive approver, so `decision_rx`
+/// is never resolved.
 async fn run_gated(
     tool: &str,
     decision_rx: oneshot::Receiver<Decision>,
 ) -> Result<(), String> {
     let decision = tokio::select! {
         d = decision_rx => d.ok(),
-        _ = tokio::time::sleep(APPROVAL_TIMEOUT) => {
-            // No approver responded — deny (fail-closed).
-            Some(Decision::Deny)
-        }
     };
     match decision {
         Some(Decision::Allow) => exec(tool).await,
         Some(Decision::Deny) | None => Err(format!("{tool} denied")),
     }
 }
